css:
.loader {
  display: block;
  position: relative;
  height: 32px;
  width: 200px;
  background: #ffffff;
  border: 2px solid #ffffff;
  color: #df3c3c;
  overflow: hidden;
}
.loader::before {
  content: "";
  background: #df3c3c;
  position: absolute;
  left: 0;
  top: 0;
  width: 0;
  height: 100%;
  animation: cyberFill 10s linear infinite;
}
.loader::after {
  content: "Loading";
  position: absolute;
  inset: 0;
  text-align: center;
  font-size: 18px;
  line-height: 32px;
  color: rgb(0,255,255);
  mix-blend-mode: difference;
  animation: cyberText 10s linear infinite;
}
@keyframes cyberFill { to { width: 100%; } }
@keyframes cyberText {
  0% { content: "0%"; } 25% { content: "25%"; } 50% { content: "50%"; } 75% { content: "75%"; } 100% { content: "100%"; }
}
